using Contoso.Text;

namespace Contoso.Text.Tests;

[TestClass]
public class StringFormatterTests
{
    private readonly StringFormatter _formatter = new();

    // FormatPhoneNumber tests

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_StartsWithAreaCodeInParens()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        Assert.StartsWith(result, "(555)");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_EndsWithLastFourDigits()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        Assert.EndsWith(result, "4567");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ReturnsCorrectFormat()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        Assert.AreEqual("(555) 123-4567", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_NullInput_ThrowsArgumentNullException()
    {
        Assert.ThrowsExactly<ArgumentNullException>(() => _formatter.FormatPhoneNumber(null!));
    }

    [TestMethod]
    public void FormatPhoneNumber_WrongLength_ThrowsArgumentException()
    {
        Assert.ThrowsExactly<ArgumentException>(() => _formatter.FormatPhoneNumber("123"));
    }

    // BuildGreeting tests

    [TestMethod]
    public void BuildGreeting_DefaultTitle_StartsWithDearMr()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.StartsWith(result, "Dear Mr.");
    }

    [TestMethod]
    public void BuildGreeting_DefaultTitle_EndsWithNameAndComma()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.EndsWith(result, "Smith,");
    }

    [TestMethod]
    public void BuildGreeting_CustomTitle_StartsWithDearAndTitle()
    {
        var result = _formatter.BuildGreeting("Johnson", "Dr.");

        Assert.StartsWith(result, "Dear Dr.");
    }

    [TestMethod]
    public void BuildGreeting_CustomTitle_ReturnsCorrectFormat()
    {
        var result = _formatter.BuildGreeting("Johnson", "Dr.");

        Assert.AreEqual("Dear Dr. Johnson,", result);
    }

    [TestMethod]
    public void BuildGreeting_WhitespaceName_ThrowsArgumentException()
    {
        Assert.ThrowsExactly<ArgumentException>(() => _formatter.BuildGreeting("   "));
    }

    // GenerateSlug tests

    [TestMethod]
    public void GenerateSlug_SimpleTitle_ReturnsLowercaseSlug()
    {
        var result = _formatter.GenerateSlug("Hello World");

        Assert.AreEqual("hello-world", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleWithPrefix_StartsWithExpectedSegment()
    {
        var result = _formatter.GenerateSlug("Getting Started with CSharp");

        Assert.StartsWith(result, "getting-started");
    }

    [TestMethod]
    public void GenerateSlug_TitleWithSuffix_EndsWithExpectedSegment()
    {
        var result = _formatter.GenerateSlug("Introduction to Unit Testing");

        Assert.EndsWith(result, "unit-testing");
    }

    [TestMethod]
    public void GenerateSlug_SpecialCharacters_StripsNonAlphanumeric()
    {
        var result = _formatter.GenerateSlug("C# is Great!!!");

        Assert.AreEqual("c-is-great", result);
    }

    [TestMethod]
    public void GenerateSlug_WhitespaceInput_ThrowsArgumentException()
    {
        Assert.ThrowsExactly<ArgumentException>(() => _formatter.GenerateSlug("  "));
    }

    // FormatCurrency tests

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_StartsWithDollarSign()
    {
        var result = _formatter.FormatCurrency(19.99m);

        Assert.StartsWith(result, "$");
    }

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_EndsWithTwoDecimalPlaces()
    {
        var result = _formatter.FormatCurrency(19.9m);

        Assert.EndsWith(result, ".90");
    }

    [TestMethod]
    public void FormatCurrency_CustomSymbol_StartsWithSymbol()
    {
        var result = _formatter.FormatCurrency(100m, "€");

        Assert.StartsWith(result, "€");
    }

    [TestMethod]
    public void FormatCurrency_WholeNumber_EndsWithZeroCents()
    {
        var result = _formatter.FormatCurrency(50m);

        Assert.EndsWith(result, ".00");
    }

    [TestMethod]
    public void FormatCurrency_ExactValue_ReturnsCorrectFormat()
    {
        var result = _formatter.FormatCurrency(1234.56m, "£");

        Assert.AreEqual("£1234.56", result);
    }
}

